def count_cx(circuit):
    count = 0
    for instruction in circuit:
        if instruction.name == "CX" or instruction.name == "CNOT":
            count += len(instruction.targets_copy()) // 2
    return count

try:
    tableau = stim.Tableau.from_stabilizers([stim.PauliString(s) for s in stabilizers_str], allow_underconstrained=True)
    candidate_circuit = tableau.to_circuit()
    
    cand_cx = count_cx(candidate_circuit)
    print(f"Standard Synthesis CX: {cand_cx}")
    
except Exception as e:
    print(f"Synthesis failed: {e}")
